import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, Maximize2, X, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel(); // Stop audio when changing cards
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel(); // Stop audio on flip
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  // Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if user is typing in an input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      switch (e.key) {
        case 'ArrowRight':
          nextCard();
          break;
        case 'ArrowLeft':
          prevCard();
          break;
        case ' ':
        case 'Enter':
          // Only flip if not already handled by a button focus
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault(); // Prevent scroll on Space
            flipCard();
          }
          break;
        default:
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div 
      className="flex flex-col max-w-5xl mx-auto w-full px-3 md:px-4 h-full focus:outline-none"
      role="application"
      aria-label="Anatomy Flashcards Study Tool"
    >

      {/* --- ZOOM MODAL --- */}
      {zoomedImage && (
        <div 
          className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-2 md:p-4 animate-in fade-in duration-200" 
          onClick={() => setZoomedImage(null)}
          role="dialog"
          aria-modal="true"
          aria-label="Image Preview"
        >
          <button 
            className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors focus:ring-2 focus:ring-white rounded-lg outline-none" 
            onClick={() => setZoomedImage(null)}
            aria-label="Close image preview"
          >
            <X size={28} />
          </button>
          <img 
            src={zoomedImage} 
            referrerPolicy="no-referrer"
            className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
            alt="Enlarged view" 
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}

      {/* --- TOP CONTROLS (Compact) --- */}
      <div className="flex-none mb-2 md:mb-4 flex justify-between items-center gap-2 md:gap-3 z-20">
        <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
            <div 
              className="bg-white px-2.5 py-1.5 rounded-lg border border-slate-200 shadow-sm font-black text-slate-700 text-[10px] md:text-xs tracking-wider whitespace-nowrap"
              aria-live="polite"
              aria-label={`Card ${currentIndex + 1} of ${deck.length}`}
            >
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            {/* Filter Dropdown */}
            <div className="relative flex-1 min-w-0">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-1 md:gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-2 md:px-3 transition-all focus:ring-2 focus:ring-blue-400 w-full md:w-auto justify-between md:justify-start ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                aria-haspopup="listbox"
                aria-expanded={isFilterOpen}
                aria-label="Filter cards by topic"
                >
                <div className="flex items-center gap-2 truncate">
                    <Filter size={12} className="shrink-0" />
                    <span className="truncate">{selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'All Topics'}</span>
                </div>
                <ChevronDown size={10} className={`transition-transform shrink-0 ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div 
                      className="absolute left-0 top-full mt-2 w-64 md:w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 flex flex-col max-h-[50vh] focus:outline-none"
                      onClick={(e) => e.stopPropagation()}
                      role="listbox"
                      aria-multiselectable="true"
                    >
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-xl">
                        <span className="text-xs font-bold text-slate-500 uppercase">Select Chapters</span>
                        <button 
                          onClick={() => setSelectedCategories([])} 
                          className="text-[10px] font-bold text-red-500 hover:text-red-700 focus:outline-none focus:underline"
                          aria-label="Clear all filters"
                        >
                          Reset All
                        </button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label 
                          key={cat} 
                          className="flex items-center gap-3 p-2.5 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors group"
                        >
                            <div className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors group-focus-within:ring-2 group-focus-within:ring-blue-400 ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={10} className="text-white" />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight break-words">{cat}</span>
                            <input 
                            type="checkbox" 
                            className="hidden"
                            checked={selectedCategories.includes(cat)}
                            onChange={() => toggleCategory(cat)}
                            role="option"
                            aria-selected={selectedCategories.includes(cat)}
                            />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-2 md:px-3 text-[10px] font-bold text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-wider hover:text-blue-600 hover:border-blue-200 focus:ring-2 focus:ring-blue-400 shrink-0"
            aria-label="Shuffle deck"
        >
            <Shuffle size={12} className="md:mr-1" /> <span className="hidden md:inline">Shuffle</span>
        </Button>
      </div>

      {/* --- THE CARD (Flex Filling) --- */}
      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-4">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-in-out cursor-pointer focus:outline-none focus:ring-4 focus:ring-blue-400/20 rounded-[2rem] ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); flipCard(); } }}
                role="button"
                aria-label={`Flashcard: ${isFlipped ? 'Showing Answer' : 'Showing Question'}. Click to flip.`}
                aria-live="polite"
            >

            {/* FRONT (Question) */}
            <div 
              className="absolute inset-0 w-full h-full bg-white rounded-[2rem] shadow-[0_4px_20px_rgb(0,0,0,0.05)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden"
              aria-hidden={isFlipped}
            >
              <div className="px-4 py-3 md:px-6 md:pt-5 flex justify-between items-start flex-none">
                <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50 px-2.5 py-1 rounded-full border border-slate-100">
                  Question
                </span>

                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')}
                    className={`p-1.5 md:p-2 rounded-full transition-colors focus:ring-2 focus:ring-red-400 ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-100 text-red-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-900'}`}
                    title="Read Question"
                    aria-label={isSpeaking && speakingId === currentCard.id + 'q' ? "Stop reading question" : "Read question text out loud"}
                  >
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={14} className="md:w-4 md:h-4" /> : <Volume2 size={14} className="md:w-4 md:h-4" />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-4 md:p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && (
                  <button 
                    className="mb-4 md:mb-6 flex-none bg-slate-50 p-1.5 md:p-2 rounded-xl border border-slate-100 relative group/img hover:border-blue-300 transition-colors cursor-zoom-in max-h-[35%] md:max-h-[45%] outline-none focus:ring-2 focus:ring-blue-400 flex items-center justify-center"
                    onClick={(e) => { 
                        if (!imgError) {
                            e.stopPropagation(); 
                            setZoomedImage(currentCard.questionImage!); 
                        }
                    }}
                    aria-label="Zoom in on question diagram"
                    disabled={imgError}
                  >
                    {imgError ? (
                        <div className="flex flex-col items-center justify-center p-4 text-slate-300">
                            <ImageOff size={32} strokeWidth={1.5} />
                            <span className="text-[9px] font-bold uppercase tracking-widest mt-2">Image Error</span>
                        </div>
                    ) : (
                        <>
                            <img 
                              src={currentCard.questionImage} 
                              referrerPolicy="no-referrer"
                              className="max-h-full w-auto object-contain rounded-lg mix-blend-multiply"
                              onError={() => setImgError(true)}
                              alt="Question Diagram"
                            />
                            <div className="absolute top-2 right-2 bg-white/90 p-1.5 rounded-lg text-slate-500 opacity-0 group-hover/img:opacity-100 transition-opacity shadow-sm">
                              <Maximize2 size={14} />
                            </div>
                        </>
                    )}
                  </button>
                )}
                <div 
                  className="text-base md:text-xl font-extrabold text-center text-slate-900 leading-snug"
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText }}
                />
              </div>
              <div className="h-6 md:h-8 flex-none bg-slate-50 border-t border-slate-100 flex items-center justify-center text-[8px] md:text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                Tap Card to Flip
              </div>
            </div>

            {/* BACK (Answer) */}
            <div 
              className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2rem] shadow-[0_20px_50px_rgb(15,23,42,0.3)] border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden"
              aria-hidden={!isFlipped}
            >
              <div className="px-4 py-3 md:px-6 md:pt-5 flex justify-between items-center flex-none">
                <span className="text-[9px] md:text-[10px] font-black uppercase text-emerald-400 tracking-[0.2em] bg-emerald-400/10 px-2.5 py-1 rounded-full border border-emerald-400/20">
                  Answer
                </span>

                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.answerText + ". " + (currentCard.explanation || ""), currentCard.id + 'a')}
                    className={`p-1.5 md:p-2 rounded-full transition-colors focus:ring-2 focus:ring-red-400 ${isSpeaking && speakingId === currentCard.id + 'a' ? 'bg-red-500/20 text-red-400' : 'bg-white/10 text-white/50 hover:bg-white/20 hover:text-white'}`}
                    title="Read Answer"
                    aria-label={isSpeaking && speakingId === currentCard.id + 'a' ? "Stop reading answer" : "Read answer text out loud"}
                  >
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={14} className="md:w-4 md:h-4" /> : <Volume2 size={14} className="md:w-4 md:h-4" />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-4 md:p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && (
                  <button 
                    className="mb-4 md:mb-6 flex-none bg-white p-1.5 md:p-2 rounded-xl relative group/img cursor-zoom-in max-h-[35%] md:max-h-[45%] outline-none focus:ring-2 focus:ring-blue-400 flex items-center justify-center"
                    onClick={(e) => { 
                        if (!ansImgError) {
                            e.stopPropagation(); 
                            setZoomedImage(currentCard.answerImage!); 
                        }
                    }}
                    aria-label="Zoom in on answer diagram"
                    disabled={ansImgError}
                  >
                    {ansImgError ? (
                        <div className="flex flex-col items-center justify-center p-4 text-slate-400">
                            <ImageOff size={32} strokeWidth={1.5} />
                            <span className="text-[9px] font-bold uppercase tracking-widest mt-2">Image Error</span>
                        </div>
                    ) : (
                        <>
                            <img 
                              src={currentCard.answerImage} 
                              referrerPolicy="no-referrer"
                              className="max-h-full w-auto object-contain rounded-lg"
                              onError={() => setAnsImgError(true)}
                              alt="Answer Diagram"
                            />
                            <div className="absolute top-2 right-2 bg-black/10 p-1.5 rounded-lg text-slate-700 opacity-0 group-hover/img:opacity-100 transition-opacity">
                              <Maximize2 size={14} />
                            </div>
                        </>
                    )}
                  </button>
                )}

                <div 
                  className="text-base md:text-2xl font-bold text-center text-white leading-relaxed mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />

                {currentCard.explanation && (
                  <div className="bg-slate-800/50 p-3 md:p-4 rounded-xl border border-slate-700/50 text-slate-300 text-xs md:text-sm leading-relaxed max-w-lg text-center backdrop-blur-sm">
                    <span className="text-slate-500 font-bold uppercase text-[9px] md:text-[10px] tracking-widest block mb-1">Explanation</span>
                    <span dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
              <div className="h-6 md:h-8 flex-none bg-slate-950/30 border-t border-slate-800/50 flex items-center justify-center text-[8px] md:text-[9px] font-bold text-slate-600 uppercase tracking-[0.2em]">
                Tap to Flip Back
              </div>
            </div>
          </div>
        ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-3xl border-2 border-dashed border-slate-300 text-slate-400 p-8 text-center" role="status">
                <Filter size={48} className="mb-4 opacity-20" />
                <p className="font-bold text-lg">No cards found in this filter.</p>
                <button 
                  onClick={() => setSelectedCategories([])} 
                  className="mt-2 text-blue-500 font-bold hover:underline focus:ring-2 focus:ring-blue-400 p-1 rounded"
                >
                  Reset Filters
                </button>
            </div>
        )}
      </div>

      {/* --- BOTTOM CONTROLS (Navigation) --- */}
      <div className="flex-none flex items-center justify-center gap-3 md:gap-4 w-full mb-2">
        <button 
          onClick={prevCard}
          disabled={currentIndex === 0}
          className="h-12 w-14 md:h-14 md:w-20 rounded-2xl bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center shrink-0 focus:ring-4 focus:ring-blue-400/20 outline-none active:scale-95"
          aria-label="Previous card"
        >
          <ChevronLeft size={24} className="md:w-7 md:h-7" />
        </button>

        <button 
          onClick={flipCard} 
          className="h-12 md:h-14 flex-1 max-w-xs rounded-2xl bg-slate-900 text-white font-bold uppercase tracking-widest shadow-xl shadow-slate-900/20 hover:bg-blue-600 hover:shadow-blue-600/30 active:scale-95 transition-all flex items-center justify-center gap-3 text-[10px] md:text-xs focus:ring-4 focus:ring-blue-400/30 outline-none"
          aria-label={isFlipped ? "Show question side" : "Show answer side"}
        >
          <RotateCw size={14} className={`md:w-4 md:h-4 ${isFlipped ? "-rotate-180 transition-transform duration-500" : "transition-transform duration-500"}`} />
          {isFlipped ? 'Question' : 'Answer'}
        </button>

        <button 
          onClick={nextCard}
          disabled={currentIndex === deck.length - 1}
          className="h-12 w-14 md:h-14 md:w-20 rounded-2xl bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center shrink-0 focus:ring-4 focus:ring-blue-400/20 outline-none active:scale-95"
          aria-label="Next card"
        >
          <ChevronRight size={24} className="md:w-7 md:h-7" />
        </button>
      </div>
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  LayoutGrid, 
  Image as ImageIcon, 
  Zap, 
  Hash, 
  Filter, 
  CheckCircle2,
  Lightbulb, 
  Shuffle,
  Maximize2,
  Play,
  Trophy,
  Target,
  Eye,
  List,
  BarChart3,
  AlertTriangle,
  Medal,
  Dna,
  Layers,
  RotateCw,
  ThumbsUp,
  ThumbsDown,
  ImageOff
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes' | 'flashcard'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);
  const [isFlipped, setIsFlipped] = useState(false);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);

  // Mobile Nav State
  const [isMobileNavOpen, setIsMobileNavOpen] = useState(false);

  // History
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.shuffleQuestions !== undefined) setShuffleQuestions(parsed.shuffleQuestions);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      shuffleQuestions
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, shuffleQuestions]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id);
        } else if (q.userAnswer === 'incorrect') {
          newMistakes.add(q.id);
        } else if (q.userAnswer && q.userAnswer !== q.correctOption) {
           newMistakes.add(q.id);
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setImgError(false);
    setIsFlipped(false);
