  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
