                <p className="text-center text-xs font-bold text-slate-400 mt-4 uppercase tracking-widest">
                  {maxPossibleQuestions > 0 ? `Ready to launch with ${questionCount} questions` : 'Adjust filters to continue'}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  const QuestionNavigator = () => {
    const answeredCount = questions.filter(q => q.userAnswer).length;

    return (
      <div className="bg-white rounded-2xl lg:rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full lg:max-h-[calc(100vh-8rem)]">
        <div className="flex-none p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="flex items-center justify-between mb-4">
             <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Session Status</span>
             <div className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wide ${mode === 'exam' ? 'bg-red-50 text-red-600 border border-red-100' : mode === 'flashcard' ? 'bg-amber-50 text-amber-600 border border-amber-100' : 'bg-blue-50 text-blue-600 border border-blue-100'}`}>
                {mode}
             </div>
          </div>

          <div className="flex items-center gap-2 mb-2">
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Time</span>
                <span className={`block font-mono font-black text-base ${timeLeft < 60 ? 'text-red-500 animate-pulse' : 'text-slate-800'}`}>
                   {(mode === 'practice' || mode === 'flashcard') ? '--:--' : formatTime(timeLeft)}
                </span>
             </div>
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Solved</span>
                <span className="block font-mono font-black text-base text-slate-800">
                   {answeredCount}<span className="text-slate-300 font-medium">/{questions.length}</span>
                </span>
             </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto min-h-0 custom-scrollbar p-3">
           <div className="grid grid-cols-5 gap-1.5">
              {questions.map((q, idx) => {
                 let statusClass = "bg-white border-slate-100 text-slate-400 hover:border-blue-200 hover:text-blue-500";
                 if (idx === currentQIndex) {
                    statusClass = "ring-2 ring-blue-500 border-blue-500 bg-blue-50 text-blue-700 z-10 shadow-md";
                 } else if (q.isFlagged) {
                    statusClass = "bg-amber-100 border-amber-300 text-amber-700";
                 } else if (q.userAnswer === 'correct') {
                    statusClass = "bg-emerald-600 border-emerald-600 text-white shadow-sm";
                 } else if (q.userAnswer === 'incorrect') {
                    statusClass = "bg-rose-600 border-rose-600 text-white shadow-sm";
                 } else if (q.userAnswer) {
                    statusClass = "bg-blue-600 border-blue-600 text-white shadow-sm";
                 }

                 return (
                    <button
                      key={q.id}
                      onClick={() => {
                        setCurrentQIndex(idx);
                        setIsMobileNavOpen(false);
                      }}
                      className={`aspect-square rounded-lg border flex items-center justify-center text-xs font-black transition-all relative ${statusClass}`}
                    >
                       {idx + 1}
                       {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                    </button>
                 )
              })}
           </div>
        </div>

        <div className="flex-none p-3 border-t border-slate-100 bg-white space-y-2 shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
             <button 
                onClick={handleFinishSession}
                className={`w-full py-3 md:py-4 rounded-xl font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg text-xs transform active:scale-95 ${
                    view === 'review' 
                    ? 'bg-slate-100 text-slate-600 hover:bg-slate-200 border border-slate-200' 
                    : 'bg-slate-900 text-white hover:bg-slate-800 shadow-slate-900/20'
                }`}
            >
                {view === 'review' ? <LayoutGrid size={16} /> : <CheckCircle2 size={16} />}
                {view === 'review' ? 'End Review' : 'Submit Session'}
            </button>
            <div className="text-[9px] font-black text-slate-400 flex justify-between gap-1 uppercase tracking-tighter pt-1 px-1">
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full bg-blue-600"></div>Done</div>
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full bg-amber-400"></div>Flag</div>
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full border border-slate-200"></div>Open</div>
            </div>
        </div>
      </div>
    )
  }

  if (view === 'playing' || view === 'review') {
    return (
      <div className="h-full flex flex-col w-full bg-slate-50 relative overflow-hidden">
        <ZoomModal />

        {isMobileNavOpen && (
          <div className="fixed inset-0 z-50 bg-slate-900/40 backdrop-blur-sm lg:hidden" onClick={() => setIsMobileNavOpen(false)}>
             <div className="absolute right-0 top-0 bottom-0 w-full max-w-[280px] bg-white shadow-2xl animate-in slide-in-from-right duration-300 h-full" onClick={e => e.stopPropagation()}>
                <QuestionNavigator />
             </div>
          </div>
        )}

        <div className="max-w-[1400px] mx-auto w-full h-full p-2 md:p-4 flex gap-4 overflow-hidden">
           <div className="flex-1 flex flex-col h-full gap-2 md:gap-4 min-w-0">
              <div className="flex justify-between items-center bg-white p-2 md:p-3 rounded-2xl border border-slate-200 shadow-sm shrink-0">
                 <div className="flex items-center gap-3">
                    <span className="px-2.5 py-1 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase tracking-wider">
                       Q {currentQIndex + 1}
                    </span>
                    <span className="text-[10px] font-bold text-slate-500 truncate hidden sm:block max-w-xs uppercase tracking-wide">
                       {currentQ.data.category}
                    </span>
                 </div>

                 <div className="flex items-center gap-2">
                    <button 
                      onClick={() => setIsMobileNavOpen(true)}
                      className="lg:hidden p-2 rounded-lg bg-slate-50 border border-slate-200 text-slate-600 hover:bg-white transition-colors"
                    >
                       <List size={18} />
                    </button>
                    <button 
                      onClick={() => toggleFlag()}
                      className={`p-2 rounded-lg border transition-all flex items-center gap-2 text-[10px] font-bold uppercase tracking-wide ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-700' : 'bg-white border-slate-200 text-slate-400 hover:text-amber-500'}`}
                    >
                      <Flag size={14} className={currentQ.isFlagged ? "fill-current" : ""} />
                      <span className="hidden sm:inline">Flag</span>
                    </button>
                    <button 
                      onClick={() => {
                        if (confirm('End session and return to setup? Progress will be lost.')) {
                          setView('setup');
                          localStorage.removeItem(SESSION_KEY);
                        }
                      }}
                      className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors"
                    >
                      <X size={18} />
                    </button>
                 </div>
              </div>

              <div className="flex-1 bg-white rounded-2xl md:rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col relative">
                 <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-10">
                    <div className="max-w-3xl mx-auto space-y-4 md:space-y-8">

                       {mode === 'flashcard' && view === 'playing' ? (
                         <div className="h-full min-h-[40vh] flex flex-col">
                            <div 
                                onClick={() => setIsFlipped(!isFlipped)}
                                className={`flex-1 relative cursor-pointer perspective-1000 group transition-all duration-500 ${isFlipped ? '[transform:rotateY(180deg)]' : ''}`}
                                style={{ transformStyle: 'preserve-3d' }}
                            >
                                {/* FRONT */}
                                <div className="absolute inset-0 bg-white border-2 border-slate-100 rounded-[2rem] flex flex-col items-center justify-center p-4 md:p-8 backface-hidden shadow-sm group-hover:border-blue-200 transition-colors">
                                    <span className="text-[9px] md:text-[10px] font-black text-slate-300 uppercase tracking-widest mb-4 md:mb-6">Question Matrix</span>
                                    {currentQ.data.questionImage && (
                                        <div className="mb-4 md:mb-6 max-h-[25vh] md:max-h-[30vh] overflow-hidden flex items-center justify-center w-full">
                                            {imgError ? (
                                                <div className="flex flex-col items-center justify-center p-4 text-slate-300">
                                                    <ImageOff size={48} strokeWidth={1.5} />
                                                    <span className="text-[10px] font-bold uppercase tracking-widest mt-2">Image Error</span>
                                                </div>
                                            ) : (
                                                <img 
                                                    src={currentQ.data.questionImage} 
                                                    referrerPolicy="no-referrer"
                                                    className="max-h-full object-contain mix-blend-multiply" 
                                                    alt="Diagram" 
                                                    onError={() => setImgError(true)} 
                                                />
                                            )}
                                        </div>
                                    )}
                                    <div className="text-lg md:text-3xl font-black text-center text-slate-900 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                                    <div className="mt-6 md:mt-10 flex items-center gap-2 text-slate-400 font-bold text-xs uppercase tracking-widest">
                                        <RotateCw size={14} /> Tap to reveal answer
                                    </div>
                                </div>
                                {/* BACK */}
                                <div className="absolute inset-0 bg-slate-900 border-2 border-slate-800 rounded-[2rem] flex flex-col items-center justify-center p-4 md:p-8 backface-hidden shadow-2xl [transform:rotateY(180deg)] overflow-hidden">
                                    <div className="absolute inset-0 bg-gradient-to-br from-blue-600/5 to-transparent"></div>
                                    <span className="text-[9px] md:text-[10px] font-black text-blue-400 uppercase tracking-widest mb-4 md:mb-6 relative z-10">Scientific Response</span>
                                    <div className="text-xl md:text-4xl font-black text-center text-white leading-tight relative z-10" dangerouslySetInnerHTML={{ __html: currentQ.data.answerText }} />
                                    {currentQ.data.explanation && (
                                        <div className="mt-4 md:mt-8 bg-white/5 border border-white/10 p-3 md:p-5 rounded-2xl text-slate-400 text-xs md:text-sm max-w-md text-center leading-relaxed relative z-10">
                                            <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                        </div>
                                    )}
                                </div>
                            </div>

                            {isFlipped && !currentQ.userAnswer && (
                                <div className="flex gap-3 md:gap-4 mt-4 md:mt-8 animate-in slide-in-from-bottom-4 duration-300">
                                    <button 
                                        onClick={() => handleAnswer('incorrect')}
                                        className="flex-1 py-3 md:py-6 bg-white border-2 border-rose-100 text-rose-500 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 md:gap-3 hover:bg-rose-50 transition-all shadow-md active:scale-95 text-xs md:text-base"
                                    >
                                        <ThumbsDown size={18} className="md:w-6 md:h-6" /> Incorrect
                                    </button>
                                    <button 
                                        onClick={() => handleAnswer('correct')}
                                        className="flex-1 py-3 md:py-6 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 md:gap-3 hover:bg-emerald-500 transition-all shadow-xl shadow-emerald-500/20 active:scale-95 text-xs md:text-base"
                                    >
                                        <ThumbsUp size={18} className="md:w-6 md:h-6" /> I Knew It
                                    </button>
                                </div>
                            )}

                            {currentQ.userAnswer && (
                                <div className={`mt-4 md:mt-8 p-4 md:p-6 rounded-2xl flex items-center justify-center gap-3 md:gap-4 animate-in zoom-in-95 duration-300 ${currentQ.userAnswer === 'correct' ? 'bg-emerald-50 text-emerald-700' : 'bg-rose-50 text-rose-700'}`}>
                                    {currentQ.userAnswer === 'correct' ? <CheckCircle2 size={20} className="md:w-6 md:h-6" /> : <AlertTriangle size={20} className="md:w-6 md:h-6" />}
                                    <span className="font-black uppercase tracking-widest text-xs md:text-base">Logged as {currentQ.userAnswer}</span>
                                </div>
                            )}
                         </div>
                       ) : (
                         <>
                            <div className="flex items-start justify-between gap-4">
                                <div className="text-base md:text-xl font-bold text-slate-900 leading-relaxed tracking-tight">
                                    <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                                </div>
                            </div>

                            {currentQ.data.questionImage && (
                                <div 
                                    className="w-full bg-slate-50 rounded-2xl border border-slate-100 p-2 md:p-4 flex justify-center cursor-zoom-in hover:border-blue-200 transition-colors group relative min-h-[150px]"
                                    onClick={(e) => { 
                                        if(!imgError) {
                                            e.stopPropagation(); 
                                            setZoomedImage(currentQ.data.questionImage!); 
                                        }
                                    }}
                                >
                                    {imgError ? (
                                        <div className="flex flex-col items-center justify-center p-8 text-slate-300">
                                            <ImageOff size={48} strokeWidth={1.5} />
                                            <span className="text-[10px] font-bold uppercase tracking-widest mt-2">Image Unavailable</span>
                                        </div>
                                    ) : (
                                        <>
                                            <img 
                                            src={currentQ.data.questionImage} 
                                            referrerPolicy="no-referrer"
                                            className="max-h-[25vh] md:max-h-[35vh] object-contain mix-blend-multiply"
                                            onError={() => setImgError(true)}
                                            alt="Question Diagram"
                                            />
                                            <div className="absolute top-4 right-4 bg-white/80 backdrop-blur-sm shadow-sm p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                                <Maximize2 size={14} className="text-slate-500" />
                                            </div>
                                        </>
                                    )}
                                </div>
                            )}

                            <div className="grid grid-cols-1 gap-2 md:gap-2.5">
                                {currentQ.options.map((option, idx) => {
                                    const isSelected = currentQ.userAnswer === option;
                                    const isCorrect = option === currentQ.correctOption;
                                    const showResult = view === 'review' || (mode === 'practice' && !!currentQ.userAnswer);

                                    let btnClass = "border-2 border-slate-50 hover:border-blue-200 hover:bg-slate-50 shadow-sm";
                                    let icon = <div className="w-5 h-5 md:w-6 md:h-6 rounded-md border border-slate-200 flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:border-blue-300 group-hover:text-blue-500">{String.fromCharCode(65 + idx)}</div>;

                                    if (showResult) {
                                    if (isCorrect) {
                                        btnClass = "border-emerald-500 bg-emerald-50 ring-2 ring-emerald-500 shadow-md";
                                        icon = <div className="w-5 h-5 md:w-6 md:h-6 rounded-md bg-emerald-500 text-white flex items-center justify-center"><Check size={14} strokeWidth={3} /></div>;
                                    } else if (isSelected) {
                                        btnClass = "border-red-500 bg-red-50 ring-2 ring-red-500 shadow-md";
                                        icon = <div className="w-5 h-5 md:w-6 md:h-6 rounded-md bg-red-500 text-white flex items-center justify-center"><X size={14} strokeWidth={3} /></div>;
                                    } else {
                                        btnClass = "border-slate-50 opacity-50 grayscale scale-[0.98]";
                                    }
                                    } else if (isSelected) {
                                    btnClass = "border-blue-600 bg-blue-50 ring-2 ring-blue-600 shadow-md";
                                    icon = <div className="w-5 h-5 md:w-6 md:h-6 rounded-md bg-blue-600 text-white flex items-center justify-center font-black">{String.fromCharCode(65 + idx)}</div>;
                                    }

                                    return (
                                    <button
                                        key={idx}
                                        onClick={() => handleAnswer(option)}
                                        disabled={showResult}
                                        className={`w-full p-3 md:p-4 rounded-xl text-left transition-all duration-200 flex items-start gap-3 md:gap-4 group ${btnClass}`}
                                    >
                                        <div className="mt-0.5 shrink-0">{icon}</div>
                                        <div className={`text-sm md:text-base font-semibold leading-tight ${isSelected || (showResult && isCorrect) ? 'text-slate-900' : 'text-slate-600'}`}>
                                        <span dangerouslySetInnerHTML={{ __html: option }} />
                                        </div>
                                    </button>
                                    );
                                })}
                            </div>

                            {(view === 'review' || (mode === 'practice' && currentQ.userAnswer && showExplanations)) && (
                                <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                                    <div className={`p-4 md:p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                                        <div className="flex justify-between items-start mb-2">
                                        <h4 className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-70">
                                            <Lightbulb size={14} /> Clinical Correlation
                                        </h4>
                                        {currentQ.userAnswer !== currentQ.correctOption && (
                                            <div className="text-[9px] md:text-[10px] font-black text-rose-600 uppercase bg-white px-2 py-1 rounded border border-rose-200 animate-pulse">
                                            Incorrect Response
                                            </div>
                                        )}
                                        </div>
                                        <div className="prose prose-sm prose-slate max-w-none text-xs md:text-sm leading-relaxed text-slate-700">
                                        {currentQ.data.explanation ? (
                                            <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                        ) : (
                                            <span className="italic opacity-60">Scientific explanation pending verification. The correct answer identifies the structure as {currentQ.correctOption}.</span>
                                        )}
                                        </div>
                                    </div>
                                </div>
                            )}
                         </>
                       )}
                    </div>
                 </div>

                 <div className="p-3 md:p-4 border-t border-slate-100 bg-white flex justify-between items-center gap-3">
                    <button 
                      onClick={() => setCurrentQIndex(prev => prev - 1)}
                      disabled={currentQIndex === 0}
                      className="flex-1 md:flex-none px-4 md:px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 hover:text-slate-900 disabled:opacity-20 disabled:hover:bg-transparent transition-colors flex items-center justify-center gap-2 text-xs md:text-sm"
                    >
                       <ChevronLeft size={16} /> Prev
                    </button>

                    <div className="hidden sm:flex items-center gap-2">
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">
                          Matrix {currentQIndex + 1}
                       </span>
                       <Dna size={12} className="text-slate-200" />
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">
                          Level {questions.length}
                       </span>
                    </div>

                    {currentQIndex === questions.length - 1 ? (
                      <button 
                        onClick={handleFinishSession}
                        className="flex-1 md:flex-none px-6 md:px-8 py-3 rounded-xl bg-slate-900 text-white font-black hover:bg-blue-600 shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2 text-xs md:text-sm uppercase tracking-wider"
                      >
                        {view === 'review' ? 'End Session' : 'Submit Matrix'} <CheckCircle2 size={16} />
                      </button>
                    ) : (
                      <button 
                        onClick={() => setCurrentQIndex(prev => prev + 1)}
                        className="flex-1 md:flex-none px-6 md:px-8 py-3 rounded-xl bg-blue-600 text-white font-black hover:bg-blue-700 shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2 text-xs md:text-sm uppercase tracking-wider"
                      >
                        Next <ChevronRight size={16} />
                      </button>
                    )}
                 </div>
              </div>
           </div>

           <div className="hidden lg:block w-72 shrink-0">
              <QuestionNavigator />
           </div>
        </div>
      </div>
    );
  }

  // Results View
  if (view === 'results') {
    const totalQuestions = questions.length;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption || q.userAnswer === 'correct').length;
    const incorrectCount = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption && q.userAnswer !== 'correct').length;
    const skippedCount = totalQuestions - correctCount - incorrectCount;
    const score = Math.round((correctCount / totalQuestions) * 100);
    const isPassing = score >= 70;

    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto">
        <div className="max-w-4xl mx-auto w-full my-4 md:my-8 p-4 md:p-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
           <div className="bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
              <div className={`${isPassing ? 'bg-emerald-600' : 'bg-slate-900'} p-8 md:p-12 text-center relative overflow-hidden`}>
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                  <div className="relative z-10 flex flex-col items-center">
                      <div className="inline-flex p-4 md:p-6 rounded-full bg-white/10 backdrop-blur-md mb-6 md:mb-8 shadow-2xl ring-1 ring-white/20">
                        {isPassing ? <Trophy size={48} className="text-white md:w-16 md:h-16" strokeWidth={1.5} /> : <Target size={48} className="text-white md:w-16 md:h-16" strokeWidth={1.5} />}
                      </div>
                      <div className="space-y-2 mb-6 md:mb-8">
                        <h2 className="text-6xl md:text-8xl font-black text-white tracking-tighter leading-none">{score}<span className="text-3xl md:text-4xl align-top opacity-60">%</span></h2>
                        <div className="flex items-center justify-center gap-2 opacity-80">
                           <Medal size={16} className="text-white" />
                           <span className="text-xs md:text-sm font-bold text-white uppercase tracking-widest">{isPassing ? 'Certified Excellence' : 'Needs Improvement'}</span>
                        </div>
                      </div>
                  </div>
              </div>

              <div className="grid grid-cols-3 divide-x divide-slate-100 border-b border-slate-100 bg-white">
                 <div className="p-4 md:p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-3xl md:text-5xl font-black text-emerald-500 mb-2 group-hover:scale-110 transition-transform">{correctCount}</span>
                    <span className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-1 md:gap-2">
                       <CheckCircle2 size={12} className="text-emerald-500" /> Correct
                    </span>
                 </div>
                 <div className="p-4 md:p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-3xl md:text-5xl font-black text-rose-500 mb-2 group-hover:scale-110 transition-transform">{incorrectCount}</span>
                    <span className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-1 md:gap-2">
                       <AlertTriangle size={12} className="text-rose-500" /> Incorrect
                    </span>
                 </div>
                 <div className="p-4 md:p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-3xl md:text-5xl font-black text-slate-400 mb-2 group-hover:scale-110 transition-transform">{skippedCount}</span>
                    <span className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-1 md:gap-2">
                       <Hash size={12} /> Skipped
                    </span>
                 </div>
              </div>

              <div className="p-6 md:p-10 bg-slate-50/50 space-y-6 md:space-y-8">
                  <div className="flex flex-col gap-3 md:gap-4">
                      <button 
                        onClick={() => {
                          setView('review');
                          setCurrentQIndex(0);
