                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] md:text-[10px] font-black uppercase text-blue-500 bg-blue-50 px-2 py-1 rounded border border-blue-100 tracking-wider">
                        {q.category || 'General'}
