            className={`flex items-center justify-center gap-2 px-3 py-2.5 md:px-4 md:py-3 rounded-xl font-bold text-xs md:text-sm border transition-all shadow-sm shrink-0 ${sortOrder !== 'default' ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
          >
            <ArrowUpDown size={14} />
            <span className="hidden md:inline">{sortOrder === 'default' ? 'Sort' : sortOrder === 'asc' ? 'A-Z' : 'Z-A'}</span>
          </button>
        </div>
      </div>

      <div className="space-y-3 md:space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-300">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold">No results found.</p>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden flex flex-col md:flex-row group">
              {q.questionImage && (
                <div className="w-full md:w-48 h-40 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0">
                  <img 
                    src={q.questionImage} 
                    referrerPolicy="no-referrer"
                    alt="Diagram" 
                    className="max-w-full max-h-full object-contain rounded-lg mix-blend-multiply" 
                    loading="lazy" 
                  />
                </div>
              )}

              <div className="p-4 md:p-6 flex-1 flex flex-col gap-2 md:gap-3">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-[9px] md:text-[10px] font-black uppercase text-blue-500 bg-blue-50 px-2 py-1 rounded border border-blue-100 tracking-wider">
                        {q.category || 'General'}
                    </span>
                    {hasSupport && (
                        <button 
                          onClick={(e) => handleAudio(e, `Question: ${q.questionText}. Answer: ${q.answerText}. ${q.explanation ? 'Explanation: ' + q.explanation : ''}`, q.id)}
                          className={`p-1.5 md:p-2 rounded-full transition-all ${isSpeaking && speakingId === q.id ? 'bg-red-100 text-red-600 ring-2 ring-red-200' : 'bg-slate-50 text-slate-400 hover:bg-blue-50 hover:text-blue-600 shadow-sm'}`}
                          title="Read Question & Answer"
                        >
                          {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        </button>
                    )}
                  </div>

                  <div className="flex items-center gap-2 shrink-0">
                    {onEdit && (
                      <button 
                        onClick={() => onEdit(q.id)}
                        className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-300 hover:bg-blue-50 transition-all shadow-sm"
                        title="Edit Question"
                      >
                        <Edit2 size={16} />
                      </button>
                    )}
                    {onDelete && (
                      <button 
                        onClick={() => onDelete(q.id)}
                        className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-red-600 hover:border-red-300 hover:bg-red-50 transition-all shadow-sm"
                        title="Delete Question"
                      >
                        <Trash2 size={16} />
                      </button>
                    )}
                  </div>
                </div>

                <div>
                  <h3 
                    className="text-sm md:text-lg font-bold text-slate-900 leading-snug mb-1 md:mb-2"
                    dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }}
                  />
                  <div className="pl-3 md:pl-4 border-l-4 border-blue-500 py-1 transition-all group-hover:border-blue-600">
                    <p 
                      className="text-xs md:text-base font-medium text-slate-600 leading-relaxed"
                      dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }}
                    />
                  </div>
                </div>

                {q.explanation && (
                  <div className="mt-1 md:mt-2 bg-slate-50 p-2 md:p-3 rounded-lg border border-slate-100 text-[10px] md:text-sm text-slate-500">
                    <span className="font-bold text-slate-400 text-[9px] md:text-[10px] uppercase mr-2">Note:</span>
                    <span dangerouslySetInnerHTML={{ __html: highlightText(q.explanation, search) }} />
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 pt-4 md:pt-6">
          <button 
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Prev
          </button>

          <div className="px-3 py-1.5 md:px-4 md:py-2 bg-slate-800 text-white rounded-xl font-bold text-xs md:text-sm shadow-lg">
            Page {currentPage} / {totalPages}
          </div>

          <button 
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default QuestionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal, RefreshCw, Activity, Play, Settings, List, Check, Trash
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'create' | 'repair'>('create');

  // Repair State
  const [isBatchRepairing, setIsBatchRepairing] = useState(false);
  const [batchStatus, setBatchStatus] = useState({ current: 0, total: 0 });

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  const missingOptionsCount = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4).length;
  }, [allQuestions]);

  const questionsToRepair = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4);
  }, [allQuestions]);

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
        setActiveTab('create');
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Neural Engine...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Authenticating Secure API Link...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Navigating Web Sources...' : 'Analyzing Anatomical Data...');

      const prompt = isUrl 
        ? `TASK: Web Content Extraction.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE professional anatomical quiz question based exclusively on the content of this page.

           REQUIRED OUTPUT FORMAT (JSON ONLY):
           {
             "questionText": "Clear question using <b> for key terms",
             "answerText": "Precise correct answer",
             "explanation": "Scientific rationale formatted with HTML tags",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "Identify the anatomical system/chapter",
             "questionImage": "Direct URL to a relevant image on the page if found"
           }`
        : `TASK: Text/HTML Synthesis.
           INPUT: """${rawInput}"""
           INSTRUCTION: Extract one anatomical quiz question from the provided input. Provide 3 high-quality distractors that are similar to the answer.

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Validating Structured Output...');

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON architecture found in model response.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Success! Rendering Preview...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Architectural Failure:", error);
      setIsAiLoading(false);
      alert("The AI Architect encountered an error. This usually happens if the URL is blocked or the content is too sparse.");
    }
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
    onCancel();
  };

  const addOption = () => {
    setFormData(prev => ({
        ...prev,
        options: [...(prev.options || []), `Option ${prev.options?.length ? prev.options.length + 1 : 1}`]
    }));
  };

  const removeOption = (index: number) => {
    const newOpts = [...(formData.options || [])];
    const removedValue = newOpts[index];
    newOpts.splice(index, 1);

    // If we removed the correct answer, reset answerText or pick another? 
    // Just keep answerText, let user fix it. Or clear it.
    let newAnswer = formData.answerText;
    if (formData.answerText === removedValue) {
        // Warning: Correct answer removed
    }

    setFormData(prev => ({ ...prev, options: newOpts }));
  };

  const updateOption = (index: number, val: string) => {
    const newOpts = [...(formData.options || [])];
    const oldVal = newOpts[index];
    newOpts[index] = val;

    let newAnswer = formData.answerText;
    if (oldVal === formData.answerText) {
        newAnswer = val; // Keep correct answer synced
    }

    setFormData(prev => ({ ...prev, options: newOpts, answerText: newAnswer }));
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-950/80 backdrop-blur-xl overflow-y-auto">
      <div className="max-w-7xl mx-auto p-4 md:p-12 space-y-12 pb-48 animate-in fade-in duration-300">

        <div className="flex justify-between items-center">
            <button onClick={resetSystem} className="text-white hover:text-slate-300 transition-colors flex items-center gap-2">
                <X size={24} /> Close Builder
            </button>
        </div>

        {!showPreview && (
          // ... (Input Section - Kept same as previous but cleaner for brevity, focus on Manual Override enhancement)
          <div className="relative bg-slate-900 rounded-[3.5rem] shadow-2xl border border-slate-800 p-8 md:p-20 space-y-12">
             <div className="space-y-6">
                <h2 className="text-4xl md:text-5xl font-black text-white">AI <span className="text-blue-500">Architect</span></h2>
                <textarea
                    value={rawInput}
                    onChange={(e) => setRawInput(e.target.value)}
                    className="w-full h-64 p-8 bg-slate-950/50 text-white rounded-3xl border-2 border-slate-800 focus:border-blue-500 outline-none text-xl resize-none"
                    placeholder="Paste text notes or URL here to generate a question..."
                />
                <div className="flex gap-4">
                    <button 
                        onClick={processEverythingWithAI}
                        disabled={isAiLoading || !rawInput.trim()}
                        className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-bold uppercase tracking-widest hover:bg-blue-500 disabled:opacity-50"
                    >
                        {isAiLoading ? 'Processing...' : 'Generate with AI'}
                    </button>
                    <button 
                        onClick={() => { setShowPreview(true); setIsManualEdit(true); }}
                        className="px-8 py-4 bg-slate-800 text-white rounded-2xl font-bold uppercase tracking-widest hover:bg-slate-700"
                    >
                        Skip to Manual
                    </button>
                </div>
             </div>
          </div>
        )}

        {/* PHASE 2: THE PUBLISHING AND REVIEW STAGE */}
        {showPreview && (
          <div className="max-w-6xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-20 duration-500">

            <div className="flex flex-col md:flex-row justify-between items-center gap-8 bg-white p-8 rounded-[3rem] border border-slate-200 shadow-2xl">
              <div className="flex items-center gap-6">
                <button 
                  onClick={() => setShowPreview(false)} 
                  className="w-16 h-16 rounded-2xl bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all flex items-center justify-center shadow-inner"
                  title="Back to Input"
                >
                  <RotateCcw size={28} />
                </button>
                <div className="h-12 w-px bg-slate-100"></div>
                <div>
                  <h3 className="text-2xl font-black text-slate-900 leading-tight">Question Editor</h3>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Review & Modify</p>
                </div>
              </div>

              <div className="flex items-center gap-5 w-full md:w-auto">
                <button 
                  onClick={() => setIsManualEdit(!isManualEdit)} 
                  className={`flex-1 md:flex-none px-10 py-5 rounded-[1.5rem] font-black text-base transition-all flex items-center justify-center gap-3 border-2 ${isManualEdit ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-500'}`}
                >
                  {isManualEdit ? <Eye size={22} /> : <Edit3 size={22} />}
                  {isManualEdit ? 'Preview' : 'Edit'}
                </button>

                <button 
                  onClick={handleGlobalPublish}
                  className="flex-1 md:flex-none px-14 py-5 bg-emerald-600 text-white font-black text-base uppercase tracking-[0.25em] rounded-[1.5rem] shadow-[0_20px_50px_rgba(16,185,129,0.3)] hover:bg-emerald-500 hover:-translate-y-2 transition-all flex items-center justify-center gap-4 active:scale-95"
                >
                  <Save size={22} />
                  Save Changes
                </button>
              </div>
            </div>

            <div className="grid lg:grid-cols-12 gap-12">
              <div className="lg:col-span-8">
                {isManualEdit ? (
                  <div className="bg-white rounded-[4rem] p-8 md:p-16 border border-slate-100 shadow-2xl space-y-12">
                    <div className="grid gap-10">
                      <div className="space-y-4">
                        <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                          <Layers size={18} className="text-blue-500" /> Classification
                        </div>
                        <input 
                          type="text" 
                          value={formData.category} 
                          onChange={e => setFormData({...formData, category: e.target.value})}
                          className="w-full p-4 md:p-6 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-xl md:text-2xl text-slate-800 outline-none focus:border-blue-500 transition-all shadow-inner"
                          placeholder="System or Chapter Title"
                        />
                      </div>

                      <div className="space-y-4">
                        <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                          <Terminal size={18} className="text-blue-500" /> Question Text (HTML Supported)
                        </div>
                        <textarea 
                          value={formData.questionText} 
                          onChange={e => setFormData({...formData, questionText: e.target.value})}
                          className="w-full h-40 p-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-medium text-lg text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                        />
                      </div>

                      <div className="space-y-6">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                                <List size={18} className="text-blue-500" /> Answer Options
                            </div>
                            <button 
                                onClick={addOption}
                                type="button" 
                                className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-600 hover:text-blue-600 rounded-xl font-bold text-xs uppercase tracking-wider flex items-center gap-2 transition-all"
                            >
                                <Plus size={14} /> Add Option
                            </button>
                        </div>

                        <div className="grid gap-4">
                          {formData.options?.map((opt, i) => (
                            <div key={i} className="flex items-center gap-3 group">
                                <button 
                                    onClick={() => setFormData({...formData, answerText: opt})}
                                    className={`w-10 h-10 shrink-0 rounded-xl flex items-center justify-center transition-all ${opt === formData.answerText ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-200' : 'bg-slate-100 text-slate-300 hover:bg-slate-200'}`}
                                    title={opt === formData.answerText ? "Correct Answer" : "Mark as Correct"}
                                >
                                    <Check size={20} strokeWidth={3} />
                                </button>
                                <div className="flex-1 relative">
                                    <input 
                                        type="text" 
                                        value={opt} 
                                        onChange={e => updateOption(i, e.target.value)}
                                        className={`w-full p-4 rounded-xl font-bold text-base outline-none transition-all border-2 ${opt === formData.answerText ? 'bg-emerald-50 border-emerald-200 text-emerald-900' : 'bg-slate-50 border-slate-100 text-slate-700 focus:border-blue-500'}`}
                                    />
                                    <div className="absolute right-3 top-1/2 -translate-y-1/2 text-xs font-black text-slate-300 pointer-events-none">{String.fromCharCode(65 + i)}</div>
                                </div>
                                <button 
                                    onClick={() => removeOption(i)}
                                    className="w-10 h-10 shrink-0 rounded-xl flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"
                                    title="Remove Option"
                                >
                                    <Trash size={18} />
                                </button>
                            </div>
                          ))}
                          {(!formData.options || formData.options.length === 0) && (
                              <div className="text-center p-8 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200 text-slate-400 font-bold text-sm">
                                  No options added. Click "Add Option" to begin.
                              </div>
                          )}
                        </div>
                      </div>

                      <div className="space-y-4">
                        <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                          <Beaker size={18} className="text-blue-500" /> Explanation
                        </div>
                        <textarea 
                          value={formData.explanation} 
                          onChange={e => setFormData({...formData, explanation: e.target.value})}
                          className="w-full h-40 p-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-medium text-base text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                        />
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="bg-white rounded-[4rem] shadow-[0_60px_150px_rgba(0,0,0,0.1)] border border-slate-100 overflow-hidden flex flex-col group transition-all duration-700 hover:shadow-[0_80px_200px_rgba(0,0,0,0.12)]">
                    <div className="bg-slate-950 p-10 flex justify-between items-center">
                      <span className="text-xs font-black text-blue-400 uppercase tracking-[0.5em] font-mono flex items-center gap-3">
                         <ShieldCheck size={18} className="animate-pulse" /> Preview Mode
                      </span>
                    </div>

                    <div className="p-12 md:p-24 space-y-16">
                      <div className="space-y-10">
                         <div className="px-8 py-3 bg-blue-50 rounded-2xl w-fit border-2 border-blue-100 shadow-sm">
                            <span className="text-sm font-black text-blue-600 uppercase tracking-widest">{formData.category || 'Uncategorized'}</span>
                         </div>

                         <h3 className="text-4xl md:text-5xl font-black text-slate-900 leading-tight tracking-tighter" dangerouslySetInnerHTML={{ __html: formData.questionText }} />

                         {formData.questionImage && (
                             <img src={formData.questionImage} alt="Visual" referrerPolicy="no-referrer" className="rounded-2xl max-h-64 object-contain mx-auto" />
                         )}
                      </div>

