                    <span className="text-xs font-black text-blue-400 uppercase tracking-[0.5em] font-mono flex items-center gap-3">
                       <ShieldCheck size={18} className="animate-pulse" /> Preview Mode
                    </span>
                  </div>

                  <div className="p-12 md:p-24 space-y-16">
                    <div className="space-y-10">
                       <div className="px-8 py-3 bg-blue-50 rounded-2xl w-fit border-2 border-blue-100 shadow-sm">
                          <span className="text-sm font-black text-blue-600 uppercase tracking-widest">{formData.category}</span>
                       </div>

                       <h3 className="text-3xl md:text-5xl font-black text-slate-900 leading-tight tracking-tighter" dangerouslySetInnerHTML={{ __html: formData.questionText }} />
                    </div>

                    <div className="grid gap-6">
                      {formData.options.map((opt, i) => (
                        <div key={i} className={`p-6 rounded-[2rem] border-4 flex items-center gap-6 transition-all duration-500 ${opt === formData.answerText ? 'border-emerald-500 bg-emerald-50/50 shadow-xl shadow-emerald-100' : 'border-slate-50 bg-slate-50/30 text-slate-400'}`}>
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-xl shadow-lg ${opt === formData.answerText ? 'bg-emerald-600 text-white' : 'bg-white border-2 border-slate-100 text-slate-300'}`}>
                            {String.fromCharCode(65 + i)}
                          </div>
                          <div className="font-bold text-xl text-slate-800 tracking-tight" dangerouslySetInnerHTML={{ __html: opt }} />
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="lg:col-span-4 space-y-12">
              <div className="bg-white rounded-[3.5rem] p-12 border border-slate-100 shadow-3xl space-y-16 sticky top-36">
                <div className="space-y-10">
                  <h4 className="font-black text-slate-900 uppercase tracking-[0.3em] text-xs border-b border-slate-100 pb-8 flex items-center gap-3">
                    <ImageIcon size={20} className="text-blue-500" /> Digital Assets
                  </h4>

                  <div className="space-y-10">
                    <div className="space-y-4">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] px-2">Primary Asset Layer</label>
                      <input 
                        type="url" 
                        value={formData.questionImage}
                        onChange={e => setFormData({...formData, questionImage: e.target.value})}
                        className="w-full px-8 py-6 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                        placeholder="Diagram URL"
                      />
                      {formData.questionImage && (
                        <img src={formData.questionImage} className="w-full rounded-2xl border-2 border-slate-100 mt-4" alt="Preview" />
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

