import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, Database, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX, Edit3, Plus
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onEdit: (id: string) => void;
  onAdd: () => void;
}

const ITEMS_PER_PAGE = 20;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport, onEdit, onAdd }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  // Helper to remove HTML tags for searching and sorting (still used for search)
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  // Helper to escape regex characters
  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  // Helper to highlight matched terms
  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;

    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;

    terms.forEach(term => {
      const regex = new RegExp(`(${escapeRegExp(term)})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-yellow-300 text-slate-900 rounded-sm px-0.5 font-bold">$1</mark>');
    });

    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'Uncategorized'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'Uncategorized') === selectedCategory);
    }

    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);

      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }

    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }

    return result;
  }, [data, selectedCategory, search, sortOrder]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  useEffect(() => {
    return () => cancel();
  }, [currentPage, cancel]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handlePageChange = (newPage: number) => {
    cancel();
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto w-full px-3 md:px-4 pb-32">
      <div className="bg-white rounded-3xl p-4 md:p-8 border border-slate-200 shadow-xl overflow-hidden relative group mb-4">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Database size={100} className="md:w-[200px] md:h-[200px]" />
        </div>

        <div className="flex flex-col md:flex-row justify-between gap-4 md:gap-6 relative z-10">
          <div className="space-y-1 md:space-y-2">
            <h2 className="text-xl md:text-3xl font-black text-slate-900 tracking-tight">
              Knowledge <span className="text-blue-600">Index</span>
            </h2>
            <div className="flex flex-wrap items-center gap-3 md:gap-4 text-[10px] md:text-xs font-bold text-slate-500 uppercase tracking-widest">
              <span className="flex items-center gap-1"><Database size={14} className="text-blue-500" /> {data.length.toLocaleString()} Total</span>
              <span className="flex items-center gap-1"><Highlighter size={14} className="text-amber-500" /> {processedData.length.toLocaleString()} Found</span>
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={onAdd}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider transition-all shadow-lg shadow-blue-500/20"
            >
              <Plus size={14} className="md:w-4 md:h-4" /> Add New
            </button>
            <button 
              onClick={onExport}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider transition-all"
            >
              <Download size={14} className="md:w-4 md:h-4" /> Backup
            </button>
            <label className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider cursor-pointer transition-all shadow-lg">
              <Upload size={14} className="md:w-4 md:h-4" /> Restore
              <input type="file" className="hidden" accept=".json" onChange={onImport} />
            </label>
          </div>
        </div>
      </div>

      <div className="sticky top-0 pt-2 pb-2 z-30 bg-slate-50/95 backdrop-blur-sm space-y-2 transition-all">
        <div className={`relative shadow-md rounded-2xl transition-all ${search ? 'ring-2 ring-blue-400' : ''}`}>
          <input 
            type="text" 
            placeholder="Search definitions, muscles..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-10 md:pl-12 md:pr-12 py-3 md:py-3.5 rounded-2xl border-2 border-slate-200 bg-white text-sm md:text-base font-semibold text-slate-800 focus:border-blue-500 focus:ring-0 outline-none transition-all placeholder:text-slate-400"
          />
