                        </button>
                    )}
                  </div>
                  <button 
                    onClick={() => onEdit(q.id)}
                    className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all border border-transparent hover:border-blue-100 group-hover:visible"
                    title="Edit Question"
