import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';

// Modular Data Imports
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2, ArrowLeft } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);

  // Builder State
  const [isBuilderOpen, setIsBuilderOpen] = useState(false);
  const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);

  // PRIMARY DATA VAULT: Loads user modifications from local storage
  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Critical: Data Vault Access Denied", e);
      return [];
    }
  });

  // AUTO-PERSISTENCE: Every change to the vault is instantly locked into storage
  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  // KNOWLEDGE BASE COMPILER: Merges system data with user data and removes duplicates
  const allQuestions = useMemo(() => {
    // 1. Gather all raw sources
    const systemSources = [
        ...ch1,
        ...ch3,
        ...ch4,
        ...ch6,
        ...ch7,
        ...ch8,
        ...ch9,
        ...ch10,
        ...ch11
    ];

    const combinedRaw = [...userVault, ...systemSources];

    // 2. Advanced De-duplication Logic
    const uniqueMap = new Map<string, Question>();

    combinedRaw.forEach(q => {
        // Normalize: remove HTML tags, extra spaces, and lowercase
        const normalizedText = q.questionText.replace(/<[^>]*>/g, '').trim().toLowerCase();
        // Create a unique content signature using ID priority
        // If ID matches, use the one from userVault (it comes first in combinedRaw)

        if (uniqueMap.has(q.id)) {
             // If we already have this ID, it means we likely have the UserVault version
             // (since userVault is spread first). Keep the first one.
             return; 
        }

        // Also check for content duplicates if IDs are different (optional, but good for cleanliness)
        // However, for the "Edit" feature to work correctly on system questions, we must prioritize the ID match.
        uniqueMap.set(q.id, q);
    });

    // 3. Data Integrity & Option Validation Pass
    return Array.from(uniqueMap.values()).map(q => {
        // Ensure options array exists
        let cleanOptions = Array.isArray(q.options) ? [...q.options] : [];

        // Critical: Ensure the correct answer is present in options
        // We use loose comparison and trimming to catch slight variations
        const answerExists = cleanOptions.some(opt => 
            opt.trim().toLowerCase() === q.answerText.trim().toLowerCase()
        );

        if (!answerExists && q.answerText) {
            // Insert correct answer if missing
            if (cleanOptions.length >= 4) {
                cleanOptions.pop(); // Remove last distractor to make room
            }
            cleanOptions.push(q.answerText);
        }

        // Filter out empty options
        cleanOptions = cleanOptions.filter(opt => opt && opt.trim() !== '');

        return {
            ...q,
            options: cleanOptions
        };
    });
  }, [userVault]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_MASTER_VAULT_${new Date().toISOString().split('T')[0]}.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            // Merge strategy: New import overwrites existing userVault entries with same ID
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q));
            return Array.from(currentMap.values());
          });
          alert("Vault Re-Synchronized: Import Successful.");
        }
      } catch (err) {
        alert("Integrity Error: File format corrupted.");
      }
    };
    reader.readAsText(file);
  };

  const clearUserData = () => {
    if (confirm("WARNING: This will delete all your custom questions, progress, and saved edits from the Local Vault. Core system questions remain. Continue?")) {
      setUserVault([]);
      localStorage.removeItem('anatomy_ultimate_vault_v4');
      localStorage.removeItem('anatomy_quiz_session_v1');
      localStorage.removeItem('anatomy_quiz_mistakes_v1');
      window.location.reload();
    }
  };

  // --- BUILDER HANDLERS ---
  const handleSaveQuestion = (newQ: Question) => {
    setUserVault(prev => {
        // Remove existing version if present
        const filtered = prev.filter(q => q.id !== newQ.id);
        // Add new version to the top
        return [newQ, ...filtered];
    });
    setIsBuilderOpen(false);
    setEditingQuestionId(null);
  };

  const handleEditQuestion = (id: string) => {
    setEditingQuestionId(id);
    setIsBuilderOpen(true);
  };

  const handleAddNew = () => {
    setEditingQuestionId(null);
    setIsBuilderOpen(true);
  };

  const handleCloseBuilder = () => {
    setIsBuilderOpen(false);
    setEditingQuestionId(null);
  };

  if (isBuilderOpen) {
    return (
      <div className="h-[100dvh] bg-slate-50 overflow-y-auto">
         <div className="sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-slate-200 p-4">
            <div className="max-w-7xl mx-auto flex items-center justify-between">
                <button onClick={handleCloseBuilder} className="flex items-center gap-2 text-slate-600 font-bold hover:text-slate-900 transition-colors">
                    <ArrowLeft size={20} /> Back to App
                </button>
                <span className="font-black text-slate-800 uppercase tracking-widest text-sm">
                    {editingQuestionId ? 'Editing Matrix' : 'New Entry'}
                </span>
            </div>
         </div>
         <QuestionBuilder 
            allQuestions={allQuestions} 
            editingId={editingQuestionId} 
            onSave={handleSaveQuestion} 
            onCancel={handleCloseBuilder}
            existingCategories={categories}
         />
      </div>
    );
  }

  return (
    <div className="h-[100dvh] bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900 overflow-hidden">
      <Header currentMode={currentMode} onModeChange={setCurrentMode} />

      <main className="flex-1 relative overflow-hidden flex flex-col">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full overflow-hidden py-4 md:py-6"><Flashcards data={allQuestions} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full overflow-hidden"><Quiz data={allQuestions} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto py-4 md:py-6">
            <QuestionList 
                data={allQuestions} 
                onExport={exportVault} 
                onImport={importVault} 
                onEdit={handleEditQuestion}
                onAdd={handleAddNew}
            />
            <div className="flex justify-center mt-12 mb-8">
               <button onClick={clearUserData} className="flex items-center gap-2 text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest transition-colors opacity-60 hover:opacity-100">
                 <Trash2 size={14} /> Factory Reset (Clear Local Vault)
               </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

